  ('aboriginal-c5fb3965-moex-00128', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '關於法官進行民事訴訟事件之審理，下列敘述何者正確？', '["參與言詞辯論之法官有變更者，審判長不得令書記官朗讀以前之筆錄，以代替當事人陳述以前辯論之 要領", "於第一審行合議審判之事件，基於直接審理原則，法院不得命其庭員一人為受命法官行準備程序", "當事人提出之防禦方法涉及營業秘密，經當事人之聲請，法院認為適當者，得不公開審判", "法院收受訴狀後，為貫徹言詞審理原則，不得選擇以書狀先行程序之方式進行爭點之整理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00129', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列何種情形，法院於裁判前，通常應經言詞辯論？', '["因起訴不合法之駁回裁定", "第二審法院廢棄第一審違反專屬管轄判決之判決", "第一審法院之本案判決", "法院以原告之起訴，依其所訴之事實，在法律上顯無理由，所為之駁回判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00130', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列何者非債之關係發生的原因？', '["買賣契約", "動產所有權移轉", "不當得利", "侵權行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00131', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '75歲喪偶且失智的甲與守寡的長媳乙以及在上班的孫子丙同居。甲另有一個目前仍活躍於商界的79歲哥 哥丁和目前在當老師的次子戊。甲之上述親屬對甲扶養義務之順序為何？', '["乙丙丁戊", "戊丙丁乙", "丙戊乙丁", "丁戊丙乙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00132', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列何者非屬民法第184條第1項前段規定之權利？', '["身體權", "區分地上權", "純粹經濟上損失", "名譽權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00133', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列關於受監護宣告之敘述，何者正確？', '["受監護宣告之自然人喪失權利能力", "受監護宣告之自然人喪失行為能力", "受監護宣告之自然人喪失責任能力", "受監護宣告之自然人喪失結婚能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00134', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '甲與乙訂立贈與契約，將其所有之A屋贈與於乙。關於贈與契約之任意撤銷，下列敘述，何者錯誤？', '["甲與乙訂立之贈與契約，經公證後，即不得任意撤銷", "甲為履行道德上義務而為贈與者，即不得任意撤銷", "甲移轉A屋之占有於乙後，不得任意撤銷贈與契約", "甲移轉A屋所有權於乙後，不得任意撤銷贈與契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00135', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '甲將其土地分別為乙、丙、丁設定第一、二、三次序之普通抵押權，並分別擔保新臺幣（下同）180萬元、 120萬元、60萬元之債權，乙將其第一次序讓與丁，設該地抵押權實行所得價金為300萬元。乙可分得多 少錢？', '["180萬元", "135萬元", "120萬元", "60萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
